fn default_player() {
    Player {
        pos: v/ZERO, prev: v/ZERO, vel: v/ZERO,
        half: v/make(14.0, 14.0),
        aim: v/UNIT_X,
        speed_mult: 1.0,
        hp: 3.0,
        iframes: 0.0,
        stamina: 1.0,
        max_stamina: 1.0,
        noise: 0.0
    }
}

fn advance_player(player, tuning, walls, desired, speed_mult, dt) {
    // --- Stamina management ---
    // Running costs stamina; if exhausted, running is blocked until some stamina recovers.
    let exhausted = player.stamina <= 0.0
    let wants_run = speed_mult > 1.0
    let actual_mult = if wants_run && exhausted { 1.0 } else { speed_mult }
    let is_running = actual_mult > 1.0

    let stamina = if is_running {
        max(0.0, player.stamina - tuning.stamina_drain_rate * dt)
    } else {
        min(player.max_stamina, player.stamina + tuning.stamina_regen_rate * dt)
    }

    // --- Noise emission ---
    // Noise depends on whether you're moving and at what speed tier.
    let moving = v/length_sq(desired) > 0.0001
    let noise = if !moving { 0.0 }
                else if actual_mult >= tuning.run_multiplier { tuning.noise_run }
                else if actual_mult <= tuning.sneak_multiplier { tuning.noise_sneak }
                else { tuning.noise_walk }

    // --- Movement ---
    let target = v/scale(desired, tuning.max_speed * actual_mult)
    let rate = if v/length_sq(desired) < 0.0001 { tuning.friction } else { tuning.accel }
    let new_vel = approach_velocity(player.vel, target, rate, dt)
    let move_delta = v/scale(new_vel, dt)
    let res = resolve_collision(player.pos, player.half, move_delta, walls, new_vel)

    Player {
        ...player,
        pos: res.pos,
        prev: player.pos,
        vel: res.vel,
        speed_mult: actual_mult,
        stamina: stamina,
        noise: noise,
        iframes: if player.iframes > 0.0 { player.iframes - dt } else { 0.0 }
    }
}

