=> namespace main

// beagle-zelda — a port of the Bevy Zelda-like prototype to raylib + raygui.
//
// This file holds game orchestration: the World/Editor/Tool state types,
// the play-mode and editor-mode tick functions, the editor's own
// rendering (grid + selection outlines + raygui panel), save/load, and
// the main loop. Enemy simulation lives in enemies.bg, core physics
// in gameplay.bg, and world rendering in rendering.bg.

use beagle.ffi as ffi
use beagle.async as async
use ray as r
use vec as v
use gameplay as g
use enemies as e
use rendering as render

// ============================================================
// Constants
// ============================================================

// Initial window dimensions only — the window is resizable at runtime, so
// never read these in render/input paths. Query r/screen_width() live.
let INITIAL_W = 1280
let INITIAL_H = 720

let MODE_PLAYING = 0
let MODE_EDITING = 1

// All map files live under this dir as <name>.txt. Each map has its own file
// so we can add a second floor, the entry hall, etc. without touching others.
let LEVELS_DIR = "/Users/jimmyhmiller/Documents/Code/PlayGround/beagle-zelda/levels/"

// Known maps, in order. Editor Prev/Next cycles through this list. First entry
// is the startup map (the entry hall).
let MAP_NAMES = ["entry_hall", "dungeon_1"]

// Seconds to fade out (and seconds to fade back in) during a door transition.
let FADE_DURATION = 0.35

let EDITOR_CAMERA_SPEED = 600.0
let EDITOR_SELECT_RADIUS = 22.0

fn map_path(name) { LEVELS_DIR ++ name ++ ".txt" }

// Pick the "other" map for a newly-placed door. With only two maps this is
// unambiguous; later a proper target picker will replace this heuristic.
fn other_map(name) {
    let mut i = 0
    let mut found = -1
    while i < length(MAP_NAMES) {
        if MAP_NAMES[i] == name { found = i }
        i = i + 1
    }
    if found < 0 { MAP_NAMES[0] }
    else {
        let j = (found + 1) % length(MAP_NAMES)
        MAP_NAMES[j]
    }
}

// Current FPS cap. 60 at startup; F2 toggles between 60 and uncapped (0).
// Held in an atom so we don't have to thread it through the World.
let fps_cap = atom(60)

// ============================================================
// Editor state types
// ============================================================

enum Tool { Select, Wall, Monster, Sentinel, Door, Spawn, Gold }

// raygui's toggle_group writes the active tab index as an i32 into tool_slot.
// Convert at the FFI boundary so the rest of the code works with the enum.
fn int_to_tool(n) {
    if n == 1 { Tool.Wall }
    else if n == 2 { Tool.Monster }
    else if n == 3 { Tool.Sentinel }
    else if n == 4 { Tool.Door }
    else if n == 5 { Tool.Spawn }
    else if n == 6 { Tool.Gold }
    else { Tool.Select }
}

fn tool_to_int(t) {
    match t {
        Tool.Select => 0,
        Tool.Wall => 1,
        Tool.Monster => 2,
        Tool.Sentinel => 3,
        Tool.Door => 4,
        Tool.Spawn => 5,
        Tool.Gold => 6
    }
}

enum Selection {
    None,
    Wall { index },
    Monster { index },
    Sentinel { index },
    Door { index },
    Spawn { index },
    Gold { index }
}

struct Editor {
    tool              // Tool enum
    drag_start        // Vec2 world-space or null if not dragging
    selection         // Selection enum
    status_text       // short message shown in the editor HUD
    tool_slot         // ffi/Cell<I32> — raygui toggle_group reads/writes through it
    lighting_enabled  // F1 toggles the cone shader overlay + shadow mesh
}

fn default_editor() {
    Editor {
        tool: Tool.Select,
        drag_start: null,
        selection: Selection.None,
        status_text: "ready",
        tool_slot: ffi/cell(ffi/Type.I32, tool_to_int(Tool.Select)),
        lighting_enabled: true
    }
}

// ============================================================
// World state (immutable-style; each tick returns a new World)
// ============================================================

// Fade state for door-triggered map transitions. The playing tick freezes
// player+enemy simulation while the transition is non-None; the renderer
// overlays a black rectangle whose alpha = fade_t for the "teleport" feel.
enum Transition {
    None,
    Out { t, target_map, target_spawn },  // t: 0 -> 1 (fully black)
    In { t }                              // t: 1 -> 0 (fade back up)
}

struct World {
    player
    walls         // list<Wall>
    monsters      // list<Monster>
    sentinels     // list<Sentinel>
    doors         // list<Door>
    spawns        // list<Spawn>
    gold_items    // list<Gold> — pickups still on the ground
    gold_collected // int — running total picked up this session
    camera        // Vec2 center in world space
    tuning
    mode          // MODE_PLAYING or MODE_EDITING
    frame         // int
    editor        // Editor (only relevant in MODE_EDITING)
    current_map   // string — name of the currently-loaded map
    transition    // Transition enum — play-mode fade state machine
    menu_open     // bool — true when the pause menu overlay is visible
}

// Extracted from a save file OR produced by `initial_map_data`. Kept separate
// from World so callers can merge it into an existing world without leaking
// editor/shader state.
struct LevelData {
    walls
    monsters
    sentinels
    doors
    spawns
    gold_items
}

// ============================================================
// Cave-generation helpers — deterministic pseudo-random jagged
// walls and rock scatters. Used by `initial_map_data` to build
// dungeon_1 without hand-placing every AABB. `seed` is an arbitrary
// int that makes each call's noise pattern distinct.
// ============================================================

fn cave_noise(i) {
    // Three small coprime buckets combined into a [0, 1] value.
    let a = to-float((i * 37 + 11) % 17) / 17.0
    let b = to-float((i * 53 + 7) % 23) / 23.0
    let c = to-float((i * 101 + 3) % 13) / 13.0
    (a + b + c) / 3.0
}

fn cave_jitter(i) { cave_noise(i) * 2.0 - 1.0 }

fn append_all(a, b) {
    let mut result = a
    let mut i = 0
    while i < length(b) {
        result = push(result, b[i])
        i = i + 1
    }
    result
}

fn concat_all(lists) {
    let mut result = []
    let mut i = 0
    while i < length(lists) {
        result = append_all(result, lists[i])
        i = i + 1
    }
    result
}

// Beagle has floor() but no ceil — do it by hand. Also guarantees >= 1.
fn ceil_int(x) {
    let f = floor(x)
    if x - f < 0.0001 { to-int(f) } else { to-int(f) + 1 }
}

// Jagged horizontal wall spanning x0..x1 at y. `thk` is the base half-height,
// `jag` the max perpendicular jitter. Each segment overlaps its neighbour by
// ~4 px so jitter can never open a gap the player could slip through.
fn jagged_h(x0, x1, y, thk, jag, seed) {
    let mut walls = []
    let span = x1 - x0
    let desired_step = 85.0
    let n_raw = ceil_int(span / desired_step)
    let n = if n_raw < 1 { 1 } else { n_raw }
    let step = span / to-float(n)
    let mut i = 0
    while i < n {
        let sx = x0 + to-float(i) * step
        let cx = sx + step * 0.5
        let j = cave_jitter(seed * 1000 + i) * jag
        let tt = thk * (0.75 + cave_noise(seed * 1000 + i + 500) * 0.5)
        walls = push(walls, g/Wall {
            center: v/make(cx, y + j),
            half: v/make(step * 0.5 + 4.0, tt)
        })
        i = i + 1
    }
    walls
}

fn jagged_v(x, y0, y1, thk, jag, seed) {
    let mut walls = []
    let span = y1 - y0
    let desired_step = 85.0
    let n_raw = ceil_int(span / desired_step)
    let n = if n_raw < 1 { 1 } else { n_raw }
    let step = span / to-float(n)
    let mut i = 0
    while i < n {
        let sy = y0 + to-float(i) * step
        let cy = sy + step * 0.5
        let j = cave_jitter(seed * 1000 + i) * jag
        let tt = thk * (0.75 + cave_noise(seed * 1000 + i + 500) * 0.5)
        walls = push(walls, g/Wall {
            center: v/make(x + j, cy),
            half: v/make(tt, step * 0.5 + 4.0)
        })
        i = i + 1
    }
    walls
}

// Scatter `count` rocks in a rectangular area. Rock sizes vary within
// [min_size, max_size] and each has a random aspect ratio so the crowd
// doesn't look uniform.
fn rock_scatter(cx, cy, hw, hh, count, min_size, max_size, seed) {
    let mut walls = []
    let mut i = 0
    while i < count {
        let nx = cave_jitter(seed + i * 31)
        let ny = cave_jitter(seed + i * 47)
        let ns = cave_noise(seed + i * 71)
        let aspect = 0.55 + cave_noise(seed + i * 113) * 0.9
        let px = cx + nx * hw
        let py = cy + ny * hh
        let sz = min_size + ns * (max_size - min_size)
        walls = push(walls, g/Wall {
            center: v/make(px, py),
            half: v/make(sz, sz * aspect)
        })
        i = i + 1
    }
    walls
}

fn find_spawn(spawns, name) {
    let mut i = 0
    let mut found = null
    while i < length(spawns) {
        if spawns[i].name == name { found = spawns[i] }
        i = i + 1
    }
    found
}

// Hardcoded content for each known map — the fallback when its file doesn't
// exist yet. Editor Save writes to disk; subsequent boots load from disk and
// ignore this. Adding a map here + to MAP_NAMES is the whole registration.
fn initial_map_data(name) {
    if name == "entry_hall" {
        // Small rectangular room, perimeter walls, exit-door on the north wall.
        // The "shop" zone will live here later — for now it's just the hall.
        let t = 20.0   // wall thickness
        let hw = 380.0 // half-width of interior
        let hh = 240.0 // half-height of interior
        let door_hw = 48.0
        LevelData {
            walls: [
                // South wall (solid)
                g/Wall { center: v/make(0.0, 0.0 - hh - t), half: v/make(hw + t, t) },
                // East + West walls (solid)
                g/Wall { center: v/make(hw + t, 0.0), half: v/make(t, hh + t) },
                g/Wall { center: v/make(0.0 - hw - t, 0.0), half: v/make(t, hh + t) },
                // North wall split around the door opening
                g/Wall { center: v/make(0.0 - (hw + door_hw) * 0.5, hh + t),
                         half: v/make((hw - door_hw) * 0.5, t) },
                g/Wall { center: v/make((hw + door_hw) * 0.5, hh + t),
                         half: v/make((hw - door_hw) * 0.5, t) }
            ],
            monsters: [],
            sentinels: [],
            doors: [
                g/Door {
                    center: v/make(0.0, hh + t),
                    half: v/make(door_hw, t),
                    target_map: "dungeon_1",
                    target_spawn: "from_entry"
                }
            ],
            spawns: [
                g/Spawn { name: "default", pos: v/make(0.0, 0.0 - hh + 40.0) },
                g/Spawn { name: "from_dungeon", pos: v/make(0.0, hh - 60.0) }
            ],
            gold_items: []
        }
    } else if name == "dungeon_1" {
        // Cave: ~4400 x 3200 interior. Built procedurally from jagged-wall and
        // rock-scatter helpers so the outline feels organic instead of axis-
        // aligned. AABBs are still AABBs; the irregular shape comes from
        // many small rects with perpendicular jitter.
        let thk = 30.0    // base wall half-thickness
        let jag = 22.0    // perimeter jitter amplitude (< thk so no gaps open)
        let hw = 2200.0
        let hh = 1600.0
        let door_hw = 64.0
        let walls = concat_all([
            // --- Perimeter (5 jagged groups around the south door gap) ---
            jagged_h(0.0 - hw, hw, hh + thk, thk, jag, 1),
            jagged_h(0.0 - hw, 0.0 - door_hw, 0.0 - hh - thk, thk, jag, 2),
            jagged_h(door_hw, hw, 0.0 - hh - thk, thk, jag, 3),
            jagged_v(0.0 - hw - thk, 0.0 - hh, hh, thk, jag, 4),
            jagged_v(hw + thk, 0.0 - hh, hh, thk, jag, 5),

            // --- Entry corridor flanks (funnels player N from the door) ---
            jagged_h(0.0 - 600.0, 0.0 - 200.0, 0.0 - 1260.0, 24.0, 14.0, 10),
            jagged_h(200.0, 600.0, 0.0 - 1260.0, 24.0, 14.0, 11),
            jagged_v(0.0 - 700.0, 0.0 - 1260.0, 0.0 - 920.0, 24.0, 14.0, 12),
            jagged_v(700.0, 0.0 - 1260.0, 0.0 - 920.0, 24.0, 14.0, 13),

            // --- SE / SW divider (vertical rib with passage at y ~ -700) ---
            jagged_v(0.0, 0.0 - 1040.0, 0.0 - 760.0, 26.0, 16.0, 20),
            jagged_v(0.0, 0.0 - 640.0, 0.0 - 300.0, 26.0, 16.0, 21),

            // --- SW winding inner wall ---
            jagged_v(0.0 - 1000.0, 0.0 - 1420.0, 0.0 - 980.0, 26.0, 14.0, 30),
            jagged_h(0.0 - 1680.0, 0.0 - 1150.0, 0.0 - 780.0, 26.0, 14.0, 31),
            jagged_v(0.0 - 900.0, 0.0 - 800.0, 0.0 - 420.0, 26.0, 14.0, 32),

            // --- Central E-W divider with passage gaps (x≈-1000, 200, 1600) ---
            jagged_h(0.0 - 1800.0, 0.0 - 1100.0, 0.0, 28.0, 18.0, 40),
            jagged_h(0.0 - 900.0, 100.0, 0.0, 28.0, 18.0, 41),
            jagged_h(300.0, 1500.0, 0.0, 28.0, 18.0, 42),
            jagged_h(1700.0, 2150.0, 0.0, 28.0, 18.0, 43),

            // --- NW chamber rim ---
            jagged_v(0.0 - 1200.0, 180.0, 820.0, 26.0, 14.0, 50),
            jagged_h(0.0 - 1850.0, 0.0 - 1050.0, 820.0, 26.0, 14.0, 51),

            // --- Far-north divider (gap near x ~ 400-500) ---
            jagged_h(0.0 - 1100.0, 350.0, 1120.0, 28.0, 16.0, 60),
            jagged_h(700.0, 1750.0, 1120.0, 28.0, 16.0, 61),

            // --- Rock scatters per zone (stalagmites / boulders) ---
            rock_scatter(1350.0, 0.0 - 600.0, 700.0, 450.0, 22, 24.0, 70.0, 100),
            rock_scatter(0.0 - 1500.0, 0.0 - 500.0, 550.0, 450.0, 16, 26.0, 70.0, 110),
            rock_scatter(0.0 - 1500.0, 500.0, 600.0, 300.0, 14, 24.0, 65.0, 120),
            rock_scatter(1100.0, 520.0, 1000.0, 500.0, 26, 24.0, 80.0, 130),
            rock_scatter(0.0, 1360.0, 2000.0, 200.0, 20, 24.0, 65.0, 140),
            rock_scatter(0.0, 0.0 - 1050.0, 420.0, 110.0, 6, 14.0, 28.0, 150),
            rock_scatter(0.0 - 300.0, 500.0, 400.0, 350.0, 10, 20.0, 50.0, 160),
            rock_scatter(600.0, 0.0 - 250.0, 400.0, 200.0, 8, 18.0, 45.0, 170)
        ])
        // --- Guardian: the one enemy type ---
        // Large, powerful, punishing if you get caught. Moderate detection
        // range + generous notice window means you can observe its patrol and
        // slip past — but once it sees you, it's fast, relentless, and hits
        // hard. Placed ONLY at chokepoints (wall gaps) so the level geometry
        // is what makes things tense.
        let guardian = fn(pos) {
            e/Monster {
                ...e/default_monster(pos),
                half: v/make(18.0, 18.0),
                speed: 190.0,
                detection_range: 280.0,
                attack_reach: 36.0,
                strength: 2.5,
                notice_threshold: 0.6
            }
        }

        LevelData {
            walls: walls,
            monsters: [
                // Entry corridor exit — first gate, teaches the mechanic
                guardian(v/make(0.0, 0.0 - 940.0)),

                // SE/SW divider passage (gap at y ~ -700, x ~ 0)
                guardian(v/make(0.0, 0.0 - 700.0)),

                // Central E-W divider — gap at x ≈ -1000
                guardian(v/make(0.0 - 1000.0, 0.0)),

                // Central E-W divider — gap at x ≈ 200
                guardian(v/make(200.0, 0.0)),

                // Central E-W divider — gap at x ≈ 1600
                guardian(v/make(1600.0, 0.0)),

                // NW chamber entrance (gap in vertical wall at x ~ -1200)
                guardian(v/make(0.0 - 1200.0, 160.0)),

                // Far-north passage (gap at x ≈ 400-500, y ~ 1120)
                guardian(v/make(480.0, 1120.0))
            ],
            sentinels: [],
            doors: [
                g/Door {
                    center: v/make(0.0, 0.0 - hh - thk),
                    half: v/make(door_hw, thk),
                    target_map: "entry_hall",
                    target_spawn: "from_dungeon"
                }
            ],
            spawns: [
                g/Spawn { name: "default", pos: v/make(0.0, 0.0 - hh + 80.0) },
                g/Spawn { name: "from_entry", pos: v/make(0.0, 0.0 - hh + 80.0) }
            ],
            gold_items: [
                // Entry corridor
                g/Gold { pos: v/make(40.0, 0.0 - 1100.0), value: 1 },
                g/Gold { pos: v/make(0.0 - 30.0, 0.0 - 1200.0), value: 1 },
                // SE chamber
                g/Gold { pos: v/make(1100.0, 0.0 - 500.0), value: 2 },
                g/Gold { pos: v/make(1400.0, 0.0 - 800.0), value: 1 },
                g/Gold { pos: v/make(1900.0, 0.0 - 200.0), value: 3 },
                // SW chamber
                g/Gold { pos: v/make(0.0 - 1600.0, 0.0 - 600.0), value: 2 },
                g/Gold { pos: v/make(0.0 - 1400.0, 0.0 - 1000.0), value: 1 },
                // NE chamber
                g/Gold { pos: v/make(1200.0, 600.0), value: 2 },
                g/Gold { pos: v/make(1500.0, 900.0), value: 3 },
                // NW chamber
                g/Gold { pos: v/make(0.0 - 1500.0, 500.0), value: 2 },
                // Far north
                g/Gold { pos: v/make(0.0 - 800.0, 1350.0), value: 5 },
                g/Gold { pos: v/make(500.0, 1400.0), value: 3 }
            ]
        }
    } else {
        // Unknown map name — treat as a runtime error rather than returning an
        // empty placeholder. Empty maps look "fine" but hide the bug.
        throw("initial_map_data: unknown map name: " ++ name)
    }
}

fn default_player() {
    g/Player {
        pos: v/ZERO, prev: v/ZERO, vel: v/ZERO,
        half: v/make(14.0, 14.0),
        aim: v/UNIT_X,
        speed_mult: 1.0,
        hp: 3.0,
        iframes: 0.0
    }
}

// Build a World populated from `data`, with the player positioned at the
// Spawn named `spawn_name` (falls back to ZERO if missing — not a crash, since
// the editor may be mid-edit with no spawns yet).
fn world_from_data(data, map_name, spawn_name, tuning, editor, mode, frame) {
    let spawn = find_spawn(data.spawns, spawn_name)
    let p_pos = if spawn == null { v/ZERO } else { spawn.pos }
    World {
        player: g/Player { ...default_player(), pos: p_pos, prev: p_pos },
        walls: data.walls,
        monsters: data.monsters,
        sentinels: data.sentinels,
        doors: data.doors,
        spawns: data.spawns,
        gold_items: data.gold_items,
        gold_collected: 0,
        camera: p_pos,
        tuning: tuning,
        mode: mode,
        frame: frame,
        editor: editor,
        current_map: map_name,
        transition: Transition.None,
        menu_open: false
    }
}

fn initial_world() {
    let name = MAP_NAMES[0]
    let data = initial_map_data(name)
    world_from_data(data, name, "default", g/default_tuning(),
                    default_editor(), MODE_PLAYING, 0)
}

// ============================================================
// Play-mode tick
// ============================================================

// Black-alpha multiplier [0, 1] for the fade overlay. None => 0, mid-transition
// => `t`, with Out and In both storing `t` where 1 is fully black.
fn fade_alpha(world) {
    match world.transition {
        Transition.None => 0.0,
        Transition.Out { t, target_map, target_spawn } => t,
        Transition.In { t } => t
    }
}

// Scan the doors list for one whose AABB overlaps the player. Returns the
// Door or null. First hit wins — overlapping doors would be an authoring bug.
fn door_under_player(player, doors) {
    let mut i = 0
    let mut found = null
    while i < length(doors) && found == null {
        let d = doors[i]
        if v/aabb_overlap(player.pos, player.half, d.center, d.half) {
            found = d
        }
        i = i + 1
    }
    found
}

// Advance the fade state machine. While non-None, the play tick short-circuits
// player/enemy simulation so the scene is visually frozen during the fade.
fn advance_transition(world, dt) {
    match world.transition {
        Transition.None => world,
        Transition.Out { t, target_map, target_spawn } => {
            let nt = t + dt / FADE_DURATION
            if nt >= 1.0 {
                // At full black, swap maps and flip to fade-in.
                let after_switch = switch_map(world, target_map, target_spawn)
                World { ...after_switch, transition: Transition.In { t: 1.0 } }
            } else {
                World { ...world, transition: Transition.Out {
                    t: nt, target_map: target_map, target_spawn: target_spawn
                } }
            }
        },
        Transition.In { t } => {
            let nt = t - dt / FADE_DURATION
            if nt <= 0.0 {
                World { ...world, transition: Transition.None }
            } else {
                World { ...world, transition: Transition.In { t: nt } }
            }
        }
    }
}

// Check which gold items the player overlaps. Returns { remaining, collected }
// where `remaining` is the items NOT picked up, and `collected` is the total
// value of those that were.
struct PickupResult { remaining, collected }

fn collect_gold(player, gold_items) {
    let pickup_radius = 22.0   // generous — player half is 14
    let mut remaining = []
    let mut collected = 0
    let mut i = 0
    while i < length(gold_items) {
        let g = gold_items[i]
        if v/length(v/sub(player.pos, g.pos)) < pickup_radius {
            collected = collected + g.value
        } else {
            remaining = push(remaining, g)
        }
        i = i + 1
    }
    PickupResult { remaining: remaining, collected: collected }
}

fn playing_tick(world) {
    let dt = g/current_dt()
    // Freeze simulation entirely during a transition — player can't move or
    // take hits mid-fade. Camera also stops, matching the visual teleport.
    let is_transitioning = match world.transition {
        Transition.None => false,
        _ => true
    }
    if is_transitioning {
        advance_transition(world, dt)
    } else {
        let tuning = world.tuning
        let desired = g/read_desired_dir()
        let speed_mult = g/read_speed_mult(tuning)
        let player_a = g/advance_player(world.player, tuning, world.walls, desired, speed_mult, dt)
        let camera = g/update_camera(world.camera, player_a.pos, tuning.camera_smoothing, dt)
        let player_b = g/update_aim(player_a, camera)
        let monsters = e/advance_all_monsters(world.monsters, player_b.pos, world.walls, dt)
        let sentinels = e/advance_all_sentinels(world.sentinels, player_b.pos, world.walls, dt)
        let player_c = g/apply_monster_attacks(player_b, monsters, world.walls)
        // Gold pickup
        let pickup = collect_gold(player_c, world.gold_items)
        // If the player walked onto a door this tick, start the fade-out.
        let maybe_door = door_under_player(player_c, world.doors)
        let next_transition = if maybe_door == null {
            Transition.None
        } else {
            Transition.Out {
                t: 0.0,
                target_map: maybe_door.target_map,
                target_spawn: maybe_door.target_spawn
            }
        }
        World {
            ...world,
            frame: world.frame + 1,
            player: player_c,
            monsters: monsters,
            sentinels: sentinels,
            gold_items: pickup.remaining,
            gold_collected: world.gold_collected + pickup.collected,
            camera: camera,
            transition: next_transition
        }
    }
}

